INSERT INTO notes (entity_type, entity_id, content, created_by, created_at) VALUES
('company', 1, 'Acme is our largest enterprise account. Annual contract value exceeds $500K. Key decision maker is James Mitchell (CEO).', 'sales-team', '2023-01-10 09:30:00'),
('company', 1, 'Acme has three divisions - headquarters in Detroit, West in SF, and Europe in Berlin. All procurement goes through HQ.', 'sales-team', '2023-06-15 10:00:00'),
('company', 4, 'TechNova is a fast-growing mid-market tech company. Very engineering-driven culture. Priya Patel (CTO) is the champion.', 'sales-team', '2023-02-20 11:30:00'),
('company', 7, 'Stellar Health has strict compliance requirements (HIPAA). All integrations need security review. Long sales cycles.', 'sales-team', '2023-01-25 10:30:00'),
('company', 8, 'Orbit Financial is in our enterprise tier. Very price-sensitive but high volume. Catherine Park (CFO) controls budget.', 'sales-team', '2023-03-01 09:30:00'),
('company', 13, 'RedStone Energy is expanding into solar. Parent company has large budget but subsidiary decisions are more independent.', 'sales-team', '2024-01-15 10:00:00'),
('company', 16, 'Nimbus is a startup with limited budget but high growth potential. Founder Alex Tan is technical and hands-on.', 'sales-team', '2023-08-05 10:30:00'),
('company', 20, 'Ironclad Security is both a customer and a potential partner for security audits of our other clients.', 'sales-team', '2023-05-25 08:30:00'),
('contact', 1, 'James prefers phone calls over email. Best time to reach is Tuesday/Thursday mornings. Decision maker for all enterprise deals.', 'sales-rep-1', '2023-01-15 10:00:00'),
('contact', 6, 'Priya is very technical and appreciates detailed architecture discussions. She evaluates all vendor tools personally.', 'sales-rep-2', '2023-03-01 11:00:00'),
('contact', 9, 'Robert is a former client from Deloitte days. Strong relationship. Refers other consulting firms to us.', 'sales-rep-1', '2023-04-10 14:00:00'),
('contact', 11, 'Dr. Foster needs all communications CC''d to compliance team. Very thorough in evaluating vendor security posture.', 'sales-rep-3', '2023-02-01 10:00:00'),
('contact', 14, 'Catherine drives hard bargains. Always ask for multi-year commitment in exchange for discount. Respects data-driven pitches.', 'sales-rep-1', '2023-03-15 09:00:00'),
('contact', 28, 'Alex is a former developer who started Nimbus. Prefers Slack over email. Very responsive on weekends.', 'sales-rep-2', '2023-08-10 10:00:00'),
('contact', 35, 'Tyler has deep connections in the DC cybersecurity community. Good source for referrals.', 'sales-rep-3', '2023-06-01 08:00:00'),
('deal', 1, 'Closed after 4.5 months. Key factors: competitive pricing, existing relationship, and successful pilot with West division.', 'sales-rep-1', '2024-03-15 10:30:00'),
('deal', 4, 'Smooth sales cycle. TechNova was already using a trial version. Priya championed internally.', 'sales-rep-2', '2024-06-20 09:30:00'),
('deal', 6, 'Quick close due to existing relationship with Robert Chen. Minimal procurement friction.', 'sales-rep-1', '2024-05-28 11:30:00'),
('deal', 7, 'Complex deal with multiple stakeholders. EMR integration is the critical path. Need dedicated solution architect.', 'sales-rep-3', '2024-06-01 10:00:00'),
('deal', 8, 'High-value opportunity but Orbit is evaluating three other vendors. Need to differentiate on latency and compliance.', 'sales-rep-1', '2024-06-15 09:00:00'),
('deal', 9, 'Lost due to budget cuts at Orbit Ventures. Not a reflection of product fit. May revisit next fiscal year.', 'sales-rep-1', '2024-07-15 09:30:00'),
('deal', 10, 'Closed ahead of schedule. Blue Ridge was motivated by fleet efficiency losses. ROI was clear from pilot data.', 'sales-rep-2', '2024-08-25 10:30:00'),
('deal', 13, 'Very large deal with long sales cycle. SCADA replacement requires extensive safety validation. 12-18 month timeline.', 'sales-rep-3', '2024-04-10 10:30:00'),
('deal', 15, 'Atlas was looking for a fast deployment. Won on ease of use and migration tools.', 'sales-rep-1', '2024-04-22 09:30:00'),
('deal', 18, 'Lost deal. Vanguard decided to build in-house after initial phase. CFO overruled our champion.', 'sales-rep-3', '2024-08-20 09:30:00'),
('deal', 20, 'Annual retainer model works well for Ironclad. They value consistency of the testing team.', 'sales-rep-3', '2024-07-10 15:30:00'),
('deal', 25, 'Lost to competitor. Cascade chose a cheaper solution despite our better feature set. Price was deciding factor.', 'sales-rep-2', '2024-08-28 14:30:00'),
('deal', 28, 'Churned after 6 months. Harmony felt the ROI was not materializing fast enough. Need better onboarding process.', 'sales-rep-2', '2024-06-15 14:30:00'),
('company', 10, 'Blue Ridge is expanding rapidly. Opening two new distribution centers in 2025. Potential for warehouse automation deal.', 'sales-rep-2', '2024-08-01 08:30:00'),
('company', 12, 'Pinnacle is a non-profit with longer payment terms (net 60). Budget cycles align with academic calendar.', 'sales-rep-1', '2023-07-01 09:30:00'),
('contact', 17, 'Victor is a hands-on COO who wants to see live demos, not slide decks. Prefers morning meetings.', 'sales-rep-2', '2023-05-15 08:00:00'),
('contact', 32, 'Sandra has been in insurance for 30 years. Values reliability over innovation. Conservative buyer.', 'sales-rep-3', '2023-02-01 11:00:00'),
('deal', 2, 'Acme West is a warm lead due to parent company relationship. Laura Jensen is enthusiastic but needs HQ approval.', 'sales-rep-1', '2024-02-01 10:00:00'),
('deal', 16, 'Nimbus has limited budget but willing to commit to multi-year for lower annual cost. Good long-term investment.', 'sales-rep-2', '2024-06-01 10:00:00'),
('company', 18, 'Vanguard Insurance is very process-driven. All vendor evaluations go through a formal RFP process. Plan 3-month lead time.', 'sales-rep-3', '2023-02-01 11:30:00'),
('contact', 45, 'Kevin is the actuarial lead and has significant influence on technology investments at Vanguard.', 'sales-rep-3', '2024-01-15 10:00:00'),
('deal', 22, 'Renewal was straightforward. TechNova increased user count by 40%. Upsell opportunity for premium tier.', 'sales-rep-2', '2024-05-10 09:30:00'),
('company', 11, 'Cascade Media is in a competitive industry. They value speed of implementation and modern UI. Lost one deal, won another.', 'sales-rep-2', '2024-09-01 10:00:00'),
('deal', 12, 'Pinnacle LMS deal is progressing slowly due to committee-based decisions. Need patience and regular check-ins.', 'sales-rep-1', '2024-08-10 10:30:00'),
('contact', 21, 'Margaret is the key decision maker for all tech purchases at Pinnacle. She values references from other educational institutions.', 'sales-rep-1', '2023-07-15 09:00:00');
